param(
    [string]$ProjectPath = (Get-Location).Path,
    [string]$OutputRoot = "artifacts\ai-logs",
    [switch]$IncludeArchivedSessions,
    [switch]$IncludeSqlite
)

$ErrorActionPreference = "Stop"

function Normalize-PathForMatch {
    param([string]$PathValue)
    try {
        return [System.IO.Path]::GetFullPath($PathValue).ToLowerInvariant()
    } catch {
        return $PathValue.ToLowerInvariant()
    }
}

function Copy-IfExists {
    param(
        [string]$SourcePath,
        [string]$DestinationPath
    )

    if (Test-Path -LiteralPath $SourcePath) {
        $parent = Split-Path -Parent $DestinationPath
        if ($parent) {
            New-Item -ItemType Directory -Force -Path $parent | Out-Null
        }
        Copy-Item -LiteralPath $SourcePath -Destination $DestinationPath -Force
        return $true
    }

    return $false
}

$codexHome = Join-Path $env:USERPROFILE ".codex"
if (-not (Test-Path -LiteralPath $codexHome)) {
    throw "Khong tim thay thu muc $codexHome"
}

$normalizedProjectPath = Normalize-PathForMatch -PathValue $ProjectPath
$timestamp = Get-Date -Format "yyyyMMdd-HHmmss"
$bundleRoot = Join-Path $OutputRoot $timestamp
$rawRoot = Join-Path $bundleRoot "raw"
$sessionsOut = Join-Path $rawRoot "sessions"
$archivedOut = Join-Path $rawRoot "archived_sessions"
$screenshotsOut = Join-Path $bundleRoot "screenshots"

New-Item -ItemType Directory -Force -Path $sessionsOut | Out-Null
New-Item -ItemType Directory -Force -Path $screenshotsOut | Out-Null

