    created_at = (Get-Date).ToString("o")
    tool = "Codex Desktop"
    project_path = $ProjectPath
    normalized_project_path = $normalizedProjectPath
    codex_home = $codexHome
    included_archived_sessions = [bool]$IncludeArchivedSessions
    included_sqlite = [bool]$IncludeSqlite
    copied_files = @()
    matched_sessions = @()
    notes = @(
        "Them anh chup man hinh desktop vao thu muc screenshots truoc khi nop BTC.",
        "Session duoc loc bang truong cwd trong dong session_meta dau tien cua moi file jsonl."
    )
}

$topLevelCopies = @(
    @{
        Source = (Join-Path $codexHome "config.toml")
        Destination = (Join-Path $rawRoot "config.toml")
        Tag = "config"
    },
    @{
        Source = (Join-Path $codexHome "session_index.jsonl")
        Destination = (Join-Path $rawRoot "session_index.jsonl")
        Tag = "session_index"
    }
)

if ($IncludeSqlite) {
    $topLevelCopies += @(
        @{
            Source = (Join-Path $codexHome "logs_2.sqlite")
            Destination = (Join-Path $rawRoot "logs_2.sqlite")
            Tag = "sqlite_log_db"
        },
        @{
            Source = (Join-Path $codexHome "logs_2.sqlite-wal")
            Destination = (Join-Path $rawRoot "logs_2.sqlite-wal")
            Tag = "sqlite_log_db_wal"
        },
        @{
            Source = (Join-Path $codexHome "logs_2.sqlite-shm")
            Destination = (Join-Path $rawRoot "logs_2.sqlite-shm")
            Tag = "sqlite_log_db_shm"
        }
    )
}

foreach ($entry in $topLevelCopies) {
    if (Copy-IfExists -SourcePath $entry.Source -DestinationPath $entry.Destination) {
        $manifest.copied_files += [ordered]@{
            tag = $entry.Tag
            source = $entry.Source
            destination = $entry.Destination
        }
    }
}

function Collect-SessionFiles {
    param(
        [string]$RootPath,
        [string]$OutputPath,
        [string]$SessionKind
    )

    if (-not (Test-Path -LiteralPath $RootPath)) {
        return
    }

    New-Item -ItemType Directory -Force -Path $OutputPath | Out-Null

    Get-ChildItem -LiteralPath $RootPath -Recurse -File -Filter "*.jsonl" | ForEach-Object {
        $sessionFile = $_.FullName
        $firstLine = Get-Content -LiteralPath $sessionFile -TotalCount 1
        if (-not $firstLine) {
            return
        }

        try {
            $json = $firstLine | ConvertFrom-Json
        } catch {
            return
        }

        if ($json.type -ne "session_meta") {
            return
        }

        $cwd = ""
        if ($null -ne $json.payload -and $null -ne $json.payload.cwd) {
            $cwd = [string]$json.payload.cwd
        }

        if ((Normalize-PathForMatch -PathValue $cwd) -ne $normalizedProjectPath) {
            return
        }

        $relativePath = $sessionFile.Substring($RootPath.Length).TrimStart("\", "/")
        $destination = Join-Path $OutputPath $relativePath
        $copied = Copy-IfExists -SourcePath $sessionFile -DestinationPath $destination

        if ($copied) {
            $manifest.matched_sessions += [ordered]@{
                kind = $SessionKind
                session_id = $json.payload.session_id
                source = $sessionFile
                destination = $destination
                timestamp = $json.payload.timestamp
                originator = $json.payload.originator
                cli_version = $json.payload.cli_version
            }
        }
    }
}

Collect-SessionFiles -RootPath (Join-Path $codexHome "sessions") -OutputPath $sessionsOut -SessionKind "session"

