function Test-SessionSafety {
    param(
        [string]$PythonCmd,
        [string]$RepoRoot,
        [string]$SessionFile
    )

    if (-not $PythonCmd) {
        return $true
    }

    $scanScript = Join-Path $RepoRoot "scripts\scan_secrets.py"
    if (-not (Test-Path -LiteralPath $scanScript)) {
        return $true
    }

    & $PythonCmd $scanScript $SessionFile | Out-Null
    return ($LASTEXITCODE -eq 0)
}

